func findPairsWithSumLessThanOrEqualToX(arr1, arr2 []int, X int) [][]int {
	pairs := [][]int{}
	m, n := len(arr1), len(arr2)
	i, j := 0, n-1

	for i < m && j >= 0 {
		sum := arr1[i] + arr2[j]
		if sum <= X {
			// Include all pairs with arr1[i] and arr2[j-idx] for idx from 0 to j
			for idx := j; idx >= 0; idx-- {
				pairs = append(pairs, []int{arr1[i], arr2[idx]})
			}
			i++
		} else {
			j--
		}
	}

	return pairs
}
