func maxSumPath(matrix [][]int) int {
	n := len(matrix)
	dp := make([][]int, n)
	for i := range dp {
		dp[i] = make([]int, i+1)
	}

	// Initialize the last row of dp with the values from the last row of the matrix
	for i := 0; i < n; i++ {
		dp[n-1][i] = matrix[n-1][i]
	}

	// Build the dp array from bottom to top
	for i := n - 2; i >= 0; i-- {
		for j := 0; j <= i; j++ {
			// Find the maximum sum from the two possible moves
			dp[i][j] = matrix[i][j] + int(math.Max(float64(dp[i+1][j]), float64(dp[i+1][j+1])))
		}
	}

	// The maximum sum will be stored at the top of the dp array
	return dp[0][0]
}

