func minimizeTransactions(transactions map[string]map[string]int) int {
	balances := make(map[string]int)

	// Calculate net balances for each party
	for from, toBalances := range transactions {
		for to, amount := range toBalances {
			balances[from] -= amount
			balances[to] += amount
		}
	}

	// Collect non-zero balances
	nonZeroBalances := make([]int, 0)
	for _, balance := range balances {
		if balance != 0 {
			nonZeroBalances = append(nonZeroBalances, balance)
		}
	}

	return dfs(0, nonZeroBalances)
}

func dfs(idx int, balances []int) int {
	// Base case: If we've processed all balances, return 0
	if idx == len(balances) {
		return 0
	}

	// Skip balances with 0 amount
	if balances[idx] == 0 {
		return dfs(idx+1, balances)
	}

	minTransactions := int(^uint(0) >> 1) // Max int value
	for i := idx + 1; i < len(balances); i++ {
		if balances[i]*balances[idx] < 0 {
			// Opposite signs, consolidate transactions
			balances[i] += balances[idx]
			minTransactions = min(minTransactions, 1+dfs(idx+1, balances))
			balances[i] -= balances[idx] // backtrack
		}
	}

	return min(minTransactions, dfs(idx+1, balances))
}

